1. p(x) = 6x^3 + 3x^2 - 5x + 1
a=6, b=3, c=-5 \& d=1
\alpha + \beta + \gamma = \frac{-b}{a} = \frac{-3}{6} = \frac{-1}{2}
\alpha\beta + \beta\gamma + \gamma\alpha = \frac{c}{a} = \frac{-5}{6}
and, \alpha\beta\gamma = \frac{-d}{a} = \frac{-1}{6}
To find value of :- (\frac{1}{\alpha} + \frac{1}{\beta} + \frac{1}{\gamma})
= \frac{\beta\gamma + \alpha\gamma + \alpha\beta}{\alpha\beta\gamma}
putting values,
\Rightarrow \frac{(\frac{-5}{6})}{\frac{-1}{6}} = \frac{-5}{6} \times \frac{-6}{1} = 5

3) x^2 - 3x - 2
x^2 - 1x - 2x - 2
x(x-1) - 2(x-1)
(x-1)(x+2)
x = 1, -2
\alpha = 1
\beta = -2
\frac{1}{2\alpha+\beta} = \frac{1}{2-2} = \frac{1}{0} = 0
\frac{1}{2\beta+\alpha} = \frac{1}{-4+1} = \frac{1}{-3} = -\frac{1}{3}
\alpha+\beta = -1
\alpha\beta = 0
f(x) = K[x^2 - (\alpha+\beta)x + \alpha\beta]
f(x) = K[x^2 + 1x + 0]
Let K be 1
f(x) = x^2 + 1x
3) x^2-3x-2
a=1
b=-3
c=-2
\alpha+\beta = \frac{-b}{a} | \alpha\beta = \frac{c}{a}
\Rightarrow \frac{-(-3)}{1} | \Rightarrow \frac{-2}{1}
\Rightarrow +3 | \Rightarrow -2
zeros = x = \frac{1}{2\alpha+\beta}, x = \frac{1}{2\beta+\alpha}
\Rightarrow (x - \frac{1}{2\alpha+\beta})(x - \frac{1}{2\beta+\alpha})
\Rightarrow x^2 - x\frac{1}{2\beta+\alpha} - x\frac{1}{2\alpha+\beta} + \frac{1}{2\alpha+\beta} \times \frac{1}{2\beta+\alpha}
\Rightarrow x^2 - \frac{2x}{(2\beta+\alpha)(2\alpha+\beta)} + \frac{1}{(2\alpha+\beta)(2\beta+\alpha)}
\Rightarrow x^2 - \frac{2x}{4\alpha\beta + 2\beta^2 + 2\alpha^2 + \alpha\beta} + \frac{1}{4\alpha\beta + 2\beta^2 + 2\alpha^2 + \alpha\beta}
\Rightarrow x^2 - \frac{2x}{4(-2) + 2(\alpha^2+\beta^2) - 2} + \frac{1}{4(-2) + 2(\alpha^2+\beta^2) - 2}
\Rightarrow x^2 - \frac{2x}{-8 + 2((\alpha+\beta)^2 - 2\alpha\beta) - 2} + \frac{1}{-8 + 2((\alpha+\beta)^2 - 2\alpha\beta) - 2}
\Rightarrow x^2 - \frac{2x}{-8 + 2(9+4) - 2} + \frac{1}{-8 + 2(9+4) - 2}
\Rightarrow x^2 - \frac{2x}{-8 + 26 - 2} + \frac{1}{-8 + 26 - 2}
\Rightarrow x^2 - \frac{2x}{13} + \frac{1}{13} \Rightarrow 13x^2 - 2x + 1

3. 2\sqrt{3}x^2 - 5x + \sqrt{3}
2\sqrt{3}x^2 - 2x - 3x + \sqrt{3}
2x(\sqrt{3}x - 1) - \sqrt{3}(\sqrt{3}x - 1)
\Rightarrow (2x - \sqrt{3})(\sqrt{3}x - 1)
\alpha = \frac{\sqrt{3}}{2} \quad \beta = \frac{1}{\sqrt{3}} \text{ or } \frac{\sqrt{3}}{3}
K[x^2 - (\alpha + \beta)x + \alpha\beta]
\Rightarrow K[x^2 - (\frac{\sqrt{3}}{2} + \frac{\sqrt{3}}{3})x + \frac{\sqrt{3}}{2} \times \frac{1}{\sqrt{3}}]
x^2 - (\frac{\sqrt{3}}{2} + \frac{\sqrt{3}}{3})x + \frac{1}{2}
\Rightarrow x^2 - (\frac{3\sqrt{3} + 2\sqrt{3}}{6})x + \frac{1}{2}
\Rightarrow x^2 - (\frac{5\sqrt{3}}{6})x + \frac{1}{2}
\Rightarrow 6(x^2) - 5\sqrt{3}x + 3
K[x^2 - (\alpha + \beta)x + \alpha\beta]
x^2 - (\frac{\sqrt{3}}{2} + \frac{\sqrt{3}}{3})x + \frac{\sqrt{3}}{2} \times \frac{\sqrt{3}}{3}
\Rightarrow x^2 - (\frac{3\sqrt{3} + 2\sqrt{3}}{6})
K(x^2 - 2)
\Rightarrow K(x^2 - (\frac{\sqrt{3}}{2} + \frac{1}{\sqrt{3}})x + \frac{\sqrt{3}}{2} \times \frac{\sqrt{3}}{\sqrt{3}})
\Rightarrow K(x^2 - (\frac{3 + 2}{2\sqrt{3}})x + \frac{\sqrt{3}}{2\sqrt{3}})
2\sqrt{3}x^2 - 5x + \sqrt{3}
Q3. 2\sqrt{3}x^2 - 5x + \sqrt{3}
\Rightarrow 2\sqrt{3}x^2 - 2x - 3x + \sqrt{3}
\Rightarrow 2x(\sqrt{3}x - 1) - \sqrt{3}(\sqrt{3}x - 1)
\Rightarrow (2x - \sqrt{3})(\sqrt{3}x - 1)
\alpha = \frac{\sqrt{3}}{2}
\beta = \frac{1}{\sqrt{3}} \text{ or } \frac{\sqrt{3}}{3}
K[x^2 - (\alpha + \beta)x + \alpha\beta]
\Rightarrow x^2 - (\frac{\sqrt{3}}{2} + \frac{1}{\sqrt{3}})x + \frac{1}{2}
\Rightarrow x^2 - (\frac{\sqrt{3}\times\sqrt{3} + 2}{2\sqrt{3}})x + \frac{1}{2}
\Rightarrow x^2 - \frac{5}{2\sqrt{3}}x + \frac{\sqrt{3}}{2\sqrt{3}}
\frac{2\sqrt{3}x^2 - 5x + \sqrt{3}}{2\sqrt{3}}
2\sqrt{3}x^2 - 5x + \sqrt{3}

1) k[x^3 - (\alpha+\beta+\gamma)x^2 + x(\alpha\beta+\beta\gamma+\alpha\gamma) - \alpha\beta\gamma]
x^3 - (\frac{1}{2} + 1 + (-3))x^2 + x[(\frac{1}{2} \times 1) + (1 \times -3) + (-3 \times \frac{1}{2})] - \frac{1}{2} \times 1 \times -3
x^3 - \frac{0x}{2} + x(\frac{1}{2} + -3 + \frac{-3}{2}) - \frac{-3}{2}
x^3 + x(\frac{-8x}{2}) - (\frac{-3}{2})
x^3 - \frac{8x}{2} - \frac{-3}{2}
\frac{2x^3 - 8x - (-3)}{2} \Rightarrow \frac{1}{2}(2x^3 - 8x + 3)

Q3 x^2 - 3x - 2
\alpha + \beta = \frac{-b}{a}
\alpha + \beta = \frac{-(-3)}{1}
= 3
\alpha\beta = \frac{c}{a}
= -2
Let new zeroes be
A = \frac{1}{2\alpha + \beta}, B = \frac{1}{2\beta + \alpha}
A + B = \frac{1}{2\alpha + \beta} + \frac{1}{2\beta + \alpha}
= \frac{2}{2\alpha\beta(1+\beta)}
= \frac{2}{2\alpha - 2(2)}
= \frac{2}{-4 \times 2}
= \frac{2}{-8 - 4}
= \frac{1}{-4}
AB = \left(\frac{1}{2\alpha + \beta}\right)\left(\frac{1}{2\beta + \alpha}\right)
= \frac{1}{2\alpha\beta(1+1)} \quad \frac{1}{2\alpha\beta(2+\beta)}
= \frac{1}{2\alpha\beta 2\alpha - 2(3)}
= \frac{1}{-4 \times 3}
= \frac{1}{-12}
